	ppar = parent().par

	current = dat[0,0]=='True'

	if ppar.Viewonselect :
		parent().activeViewer = current

	if current:
		cue = ppar.Cueonselect
		action = int(ppar.Actionselecton)
		if action > 0 :

			ppar.Gosetcurcue = ppar.Curcueonselect				
			ppar.Gotargetcue = ppar.Cueonselect

			ppar.Goaction = action - 1

			if ppar.Playonselect :
				ppar.Gotocueplay.pulse()
			else:
				ppar.Gotocuepause.pulse()

	else:
		if ppar.Actionselectoff=='pause' :
			iop.Mv.par.Play = 0

	return

