*�����������������def onValueChange(par, val, prev):

	if par.name == 'File' :	
		parent.MvPlay.par.Sourcetype = 'filepath'

	elif par.name == 'Mvspec' :
		parent.MvPlay.par.Sourcetype = 'mvspec'

	ipar.MvPlay.Newsourcepending = True

	# if it's just starting, leave it alone, let it go
	if op('timer').segment < 4 :
		return

	osc = parent.MvPlay.par.Onsourcechange

	if osc == 'wait' :
		return

	elif osc == 'initialize' :
		ext.MvPlay.Initialize()	

	elif osc == 'start'  or  osc == 'usemvspec' :
		ext.MvPlay.Start()

	return
